// Smooth scroll - no pop-in animations
document.addEventListener("DOMContentLoaded", function () {
  // Sections are now always visible for smoother experience
  const animatedSections = document.querySelectorAll(".section-animate");
  animatedSections.forEach((section) => {
    section.classList.add("visible");
  });
});
// Dynamically update copyright year
document.getElementById("copyright-year").textContent =
  new Date().getFullYear();

// Dynamically update release date with current quarter
(function () {
  const now = new Date();
  const month = now.getMonth(); // 0-11
  const year = now.getFullYear();

  // Calculate quarter based on current month
  let quarter;
  if (month >= 0 && month <= 2)
    quarter = 1; // Jan-Mar = Q1
  else if (month >= 3 && month <= 5)
    quarter = 2; // Apr-Jun = Q2
  else if (month >= 6 && month <= 8)
    quarter = 3; // Jul-Sep = Q3
  else quarter = 4; // Oct-Dec = Q4

  const releaseDateElement = document.getElementById("release-date");
  if (releaseDateElement) {
    releaseDateElement.textContent = `Next Update Coming Q${quarter} ${year}`;
  }
})();

// Fetch and display site version
(async function () {
  try {
    const response = await fetch("version.json");
    const data = await response.json();
    const versionElement = document.getElementById("site-version");
    if (versionElement && data.version) {
      versionElement.textContent = `v${data.version}`;
      versionElement.title = `Build ${data.build} - Last updated ${new Date(data.lastUpdated).toLocaleString()}`;
    }
  } catch (error) {
    console.log("Version fetch failed, using default");
  }
})();
// Hero background video — random selection and autoplay
(function () {
  console.log("=== VIDEO DEBUG START ===");
  
  // Check if mobile device for performance
  var isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent) || window.innerWidth < 768;
  
  if (isMobile) {
    console.log("Mobile device detected, skipping video for performance");
    return;
  }
  
  var HERO_VIDEOS = [
    "media/BGVideo-optimized.mp4",
    "media/HeroVideoWorld-optimized.mp4",
  ];
  var video = document.getElementById("hero-video");

  console.log("Video element:", video);

  if (!video) {
    console.log("ERROR: Video element not found!");
    return;
  }

  if (
    window.matchMedia &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches
  ) {
    console.log("Reduced motion detected, skipping video");
    return;
  }

  if (HERO_VIDEOS.length > 0) {
    var src = HERO_VIDEOS[Math.floor(Math.random() * HERO_VIDEOS.length)];
    console.log("Selected video:", src);

    video.src = src;
    video.muted = true;
    video.playsInline = true;
    video.autoplay = true;
    video.loop = true;
    video.preload = "auto";

    console.log("Video attributes set:", {
      src: video.src,
      muted: video.muted,
      autoplay: video.autoplay,
      loop: video.loop,
      preload: video.preload,
    });

    // Load and play
    video.load();
    console.log("Video load() called");

    // Try to play immediately
    setTimeout(function () {
      console.log("Attempting to play video...");
      var playPromise = video.play();

      if (playPromise !== undefined) {
        playPromise
          .then(function () {
            console.log("✓✓✓ VIDEO IS PLAYING ✓✓✓");
          })
          .catch(function (error) {
            console.error("✗✗✗ PLAY FAILED:", error);
            console.log("Will retry on user interaction");

            // Single simple click handler
            document.addEventListener(
              "click",
              function () {
                console.log("User clicked, retrying play...");
                video
                  .play()
                  .then(function () {
                    console.log("✓✓✓ VIDEO STARTED ON CLICK ✓✓✓");
                  })
                  .catch(function (err) {
                    console.error("Still failed:", err);
                  });
              },
              { once: true },
            );
          });
      }
    }, 500);

    // Listen for video events
    video.addEventListener("playing", function () {
      console.log("EVENT: Video is playing");
    });
    video.addEventListener("pause", function () {
      console.log("EVENT: Video paused");
    });
    video.addEventListener("error", function (e) {
      console.error("VIDEO ERROR:", e);
    });
  }
  console.log("=== VIDEO DEBUG END ===");
})();

// Removed delayed font loading to avoid FOUT/pop

// Image loading optimization
function optimizeImages() {
  // Preload visible images
  const images = document.querySelectorAll('img[loading="lazy"]');
  const imageObserver = new IntersectionObserver(
    (entries, observer) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const img = entry.target;
          if (img.complete) {
            img.style.opacity = "1";
          } else {
            img.onload = function () {
              this.style.opacity = "1";
            };
          }

          observer.unobserve(img);
        }
      });
    },
    {
      rootMargin: "50px",
    },
  );

  images.forEach((img) => imageObserver.observe(img));

  // Prefetch next section images on scroll
  let prefetched = new Set();
  window.addEventListener("scroll", () => {
    const scrolled = window.scrollY;
    const windowHeight = window.innerHeight;
    const documentHeight = document.documentElement.scrollHeight;

    // Prefetch team images when halfway down
    if (scrolled > documentHeight * 0.5 && !prefetched.has("team")) {
      const teamImages = ["media/Gavin1.jpg", "media/Kirstenjpg1.jpg"];
      teamImages.forEach((src) => {
        const link = document.createElement("link");
        link.rel = "prefetch";
        link.href = src;
        document.head.appendChild(link);
      });
      prefetched.add("team");
    }
  });
}

// Initialize image optimization
if ("IntersectionObserver" in window) {
  document.addEventListener("DOMContentLoaded", optimizeImages);
}
// ===== MOBILE NAVIGATION =====
const navToggle = document.getElementById("nav-toggle");
const navMenu = document.getElementById("nav-menu");
const navOverlay = document.getElementById("nav-overlay");

function closeMobileMenu() {
  if (navToggle) navToggle.classList.remove("active");
  if (navMenu) navMenu.classList.remove("active");
  if (navOverlay) navOverlay.classList.remove("active");
  if (navToggle) navToggle.setAttribute("aria-expanded", "false");
  document.body.style.overflow = "";
}

if (navToggle && navMenu) {
  navToggle.addEventListener("click", function () {
    const isOpening = !navMenu.classList.contains("active");
    navToggle.classList.toggle("active");
    navMenu.classList.toggle("active");
    if (navOverlay) navOverlay.classList.toggle("active");
    navToggle.setAttribute(
      "aria-expanded",
      navMenu.classList.contains("active"),
    );
    document.body.style.overflow =
      isOpening && window.innerWidth <= 768 ? "hidden" : "";
  });

  if (navOverlay) {
    navOverlay.addEventListener("click", closeMobileMenu);
  }

  document.querySelectorAll(".nav-link").forEach((link) => {
    link.addEventListener("click", closeMobileMenu);
  });

  window.addEventListener("resize", function () {
    if (window.innerWidth > 768) closeMobileMenu();
  });
}

// ===== SWIPE TO CLOSE MOBILE NAV =====
(function () {
  var touchStartX = 0;
  var touchStartY = 0;
  document.addEventListener(
    "touchstart",
    function (e) {
      touchStartX = e.changedTouches[0].screenX;
      touchStartY = e.changedTouches[0].screenY;
    },
    { passive: true },
  );
  document.addEventListener(
    "touchend",
    function (e) {
      if (!navMenu || !navMenu.classList.contains("active")) return;
      var deltaX = e.changedTouches[0].screenX - touchStartX;
      var deltaY = Math.abs(e.changedTouches[0].screenY - touchStartY);
      // Swipe left (deltaX < -50) with mostly horizontal motion to close menu
      if (deltaX < -50 && deltaY < 100) {
        closeMobileMenu();
      }
    },
    { passive: true },
  );
})();

// ===== EXPANDABLE FEATURE CARDS =====
function initializeExpandableFeatures() {
  const featureCards = document.querySelectorAll(".feature-card-overlay");

  featureCards.forEach((card) => {
    card.addEventListener("click", function (e) {
      e.preventDefault();

      // Close other expanded cards first
      featureCards.forEach((otherCard) => {
        if (otherCard !== card && otherCard.classList.contains("expanded")) {
          otherCard.classList.remove("expanded");
          otherCard.setAttribute("aria-expanded", "false");
        }
      });

      // Toggle current card
      this.classList.toggle("expanded");
      this.setAttribute("aria-expanded", this.classList.contains("expanded"));

      // Add extra leaves when expanding
      if (this.classList.contains("expanded")) {
        const rect = this.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;

        // Create extra celebration leaves
        for (let i = 0; i < 8; i++) {
          setTimeout(() => {
            createLeaf(centerX, centerY, true);
          }, i * 100);
        }
      }
    });

    // Keyboard support
    card.addEventListener("keydown", function (e) {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        this.click();
      }
    });

    // Accessibility
    card.setAttribute("tabindex", "0");
    card.setAttribute("role", "button");
    card.setAttribute("aria-expanded", "false");

    const title = card.querySelector("h3");
    if (title) {
      card.setAttribute(
        "aria-label",
        `Expand details for ${title.textContent}`,
      );
    }
  });
}

// ===== SMOOTH SCROLLING =====
document.querySelectorAll('a[href^="#"]').forEach((anchor) => {
  anchor.addEventListener("click", function (e) {
    e.preventDefault();
    const target = document.querySelector(this.getAttribute("href"));
    if (target) {
      target.scrollIntoView({
        behavior: "smooth",
        block: "start",
      });
    }
  });
});

// ===== ACTIVE NAVIGATION HIGHLIGHTING =====
function setActiveNav() {
  const sections = document.querySelectorAll("section[id]");
  const navLinks = document.querySelectorAll(".nav-link");

  let current = "";
  sections.forEach((section) => {
    const sectionTop = section.offsetTop;
    const sectionHeight = section.clientHeight;
    if (scrollY >= sectionTop - 200) {
      current = section.getAttribute("id");
    }
  });

  navLinks.forEach((link) => {
    link.classList.remove("active");
    if (link.getAttribute("href") === "#" + current) {
      link.classList.add("active");
    }
  });
}

window.addEventListener("scroll", setActiveNav);

