// Timeout fallback in case iframe never triggers load/error events
setTimeout(() => {
  const loading = document.getElementById("discord-loading");
  const widget = document.getElementById("discord-widget");
  const fallback = document.getElementById("discord-fallback");

  if (loading && loading.style.display !== "none") {
    console.log("Discord widget timed out, showing fallback");
    loading.style.display = "none";
    if (fallback) fallback.style.display = "flex";
  }
}, 10000); // 10 second timeout

// ===== STEAM UPDATES SYSTEM (Steam News API) =====
async function loadSteamUpdates() {
  const loadingEl = document.getElementById("updates-loading");
  const listEl = document.getElementById("updates-list");
  const errorEl = document.getElementById("updates-error");
  const fallbackEl = document.getElementById("updates-fallback");

  const CACHE_KEY = "steam-news-cache-v5";
  const CACHE_TTL = 30 * 60 * 1000;

  try {
    let cached = null;
    try {
      cached = localStorage.getItem(CACHE_KEY);
    } catch (_) {}
    if (cached) {
      const { data, timestamp } = JSON.parse(cached);
      if (Date.now() - timestamp < CACHE_TTL) {
        displaySteamUpdates(data);
        return;
      }
    }

    const steamAppId = "2171040";
    const newsUrl = `https://api.steampowered.com/ISteamNews/GetNewsForApp/v0002/?appid=${steamAppId}&count=3&maxlength=0&format=json`;
    // Own Cloudflare Worker first (blog-backend/steam-news-worker.js),
    // third-party proxy as fallback
    const proxyUrls = [
      "https://windhelm-steam-news.windhelmthegame.workers.dev/?count=3",
      `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(newsUrl)}`,
    ];

    let newsData = null;
    for (const proxyUrl of proxyUrls) {
      try {
        const resp = await fetch(proxyUrl, {
          signal: AbortSignal.timeout(8000),
        });
        if (resp.ok) {
          newsData = await resp.json();
          if (!newsData?.appnews) newsData = null;
        }
      } catch (_) {}
      if (newsData) break;
    }

    if (!newsData) throw new Error("Steam news unavailable");

    if (newsData?.appnews?.newsitems?.length > 0) {
      const updates = newsData.appnews.newsitems.map((item) => ({
        title: item.title,
        date: new Date(item.date * 1000).toISOString(),
        content: item.contents,
        url: item.url,
        author: item.author || "Steam News",
        eventHeader: item.feedlabel || null,
      }));

      try {
        localStorage.setItem(
          CACHE_KEY,
          JSON.stringify({ data: updates, timestamp: Date.now() }),
        );
      } catch (_) {}

      displaySteamUpdates(updates);
      return;
    }

    throw new Error("No news items in response");
  } catch (error) {
    showSteamError();
  }
}

function displaySteamUpdates(updates) {
  // Sort newest first, show only latest 3
  updates = [...updates]
    .sort((a, b) => new Date(b.date) - new Date(a.date))
    .slice(0, 3);

  const loadingEl = document.getElementById("updates-loading");
  const listEl = document.getElementById("updates-list");

  loadingEl.style.display = "none";
  listEl.style.display = "block";

  const fallbackImgUrl =
    "https://cdn.akamai.steamstatic.com/steam/apps/2171040/header.jpg";
  listEl.innerHTML = updates
    .map((update) => {
      // Extract first image from HTML or Steam BBCode variants
      let imgUrl = null;
      const contentStr = update.content || "";
      const CLAN_IMG = "https://clan.fastly.steamstatic.com/images";
      // [img src="{STEAM_CLAN_IMAGE}/id/hash.ext"][/img]
      const bbSrcMatch = contentStr.match(
        /\[img\s+src=["']?\{STEAM_CLAN_IMAGE\}([^"'\]]+)["']?\]/i,
      );
      // [img]url[/img]
      const bbPlainMatch = contentStr.match(/\[img\]([^\[]+?)\[\/img\]/i);
      // <img src="url">
      const htmlImgMatch = contentStr.match(
        /<img[^>]+src=["']([^"']+)["'][^>]*>/i,
      );
      if (bbSrcMatch) {
        imgUrl = CLAN_IMG + bbSrcMatch[1].trim();
      } else if (bbPlainMatch) {
        imgUrl = bbPlainMatch[1].trim().replace("{STEAM_CLAN_IMAGE}", CLAN_IMG);
      } else if (htmlImgMatch) {
        imgUrl = htmlImgMatch[1];
      }
      if (imgUrl && imgUrl.startsWith("//")) {
        imgUrl = "https:" + imgUrl;
      }

      const thumbHtml = imgUrl
        ? `<img class="blog-thumb" src="${imgUrl}" alt="${escapeHtml(update.title)} thumbnail" loading="lazy">`
        : `<div class="blog-thumb-placeholder"><img src="${fallbackImgUrl}" alt="Windhelm logo"></div>`;

      // Strip images and BBCode from content for excerpt
      const plainContent = contentStr
        .replace(/<img[^>]*>/gi, "")
        .replace(/\[img\][\s\S]*?\[\/img\]/gi, "")
        .replace(/\[url=[^\]]+\]([^\[]+)\[\/url\]/gi, "$1")
        .replace(/<[^>]+>/g, "")
        .replace(/\[.*?\]/g, "")
        .replace(/\n+/g, " ")
        .trim();
      const excerpt =
        plainContent.length > 280
          ? plainContent.slice(0, 277) + "…"
          : plainContent;

      const authorLabel =
        update.author && update.author !== "Steam News"
          ? `Posted by ${escapeHtml(update.author)}`
          : "Posted by Windhelm Team";

      return `
          <div class="blog-post">
            ${thumbHtml}
            <div class="blog-body">
              <a class="blog-title" href="${update.url}" target="_blank" rel="noopener noreferrer">${escapeHtml(update.title)}</a>
              <p class="blog-excerpt">${escapeHtml(excerpt)}</p>
              <div class="blog-meta">
                <span>${formatDate(update.date)}</span>
                <span>${authorLabel}</span>
              </div>
            </div>
          </div>`;
    })
    .join("");

  console.log(`Displayed ${updates.length} Steam blog posts`);
}

