function formatDate(dateString) {
  const date = new Date(dateString);
  return date.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

function formatUpdateContent(content) {
  // Convert simple markdown and Steam BBCode to HTML
  return (
    content
      // Bold markdown
      .replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>")
      // Bullet formatting
      .replace(/• /g, "<br>• ")
      // Steam BBCode image
      .replace(/\[img\]([^\[]+?)\[\/img\]/gi, (_match, url) => {
        const normalized = url.startsWith("//") ? "https:" + url : url;
        return `<div style="text-align:center;margin:0.5em 0;"><img src="${normalized}" alt="Update image" style="max-width:100%;border-radius:8px;box-shadow:0 2px 12px #0003;"></div>`;
      })
      // Steam BBCode URL
      .replace(
        /\[url=([^\]]+)\]([^\[]+)\[\/url\]/gi,
        (_m, href, text) =>
          `<a href="${href}" target="_blank" rel="noopener">${text}</a>`,
      )
      // Newlines
      .replace(/\n/g, "<br>")
      .trim()
  );
}

function escapeHtml(text) {
  const div = document.createElement("div");
  div.textContent = text;
  return div.innerHTML;
}

// ===== PERFORMANCE MONITORING =====
function logPerformance() {
  if ("performance" in window) {
    window.addEventListener("load", () => {
      setTimeout(() => {
        const perf = performance.getEntriesByType("navigation")[0];
        if (perf) {
          console.log("Page Load Performance:", {
            "DOM Content Loaded": Math.round(
              perf.domContentLoadedEventEnd - perf.domContentLoadedEventStart,
            ),
            "Full Load Time": Math.round(
              perf.loadEventEnd - perf.loadEventStart,
            ),
            "DNS Lookup": Math.round(
              perf.domainLookupEnd - perf.domainLookupStart,
            ),
            "Connect Time": Math.round(perf.connectEnd - perf.connectStart),
          });
        }

        // Track Core Web Vitals
        if ("PerformanceObserver" in window) {
          // Largest Contentful Paint (LCP)
          try {
            const lcpObserver = new PerformanceObserver((list) => {
              const entries = list.getEntries();
              const lastEntry = entries[entries.length - 1];
              console.log(
                "LCP (Largest Contentful Paint):",
                Math.round(lastEntry.renderTime || lastEntry.loadTime),
                "ms",
              );
            });
            lcpObserver.observe({
              type: "largest-contentful-paint",
              buffered: true,
            });
          } catch (e) {}

          // First Input Delay (FID)
          try {
            const fidObserver = new PerformanceObserver((list) => {
              const entries = list.getEntries();
              entries.forEach((entry) => {
                console.log(
                  "FID (First Input Delay):",
                  Math.round(entry.processingStart - entry.startTime),
                  "ms",
                );
              });
            });
            fidObserver.observe({ type: "first-input", buffered: true });
          } catch (e) {}

          // Cumulative Layout Shift (CLS)
          try {
            let clsScore = 0;
            const clsObserver = new PerformanceObserver((list) => {
              for (const entry of list.getEntries()) {
                if (!entry.hadRecentInput) {
                  clsScore += entry.value;
                }
              }
              console.log(
                "CLS (Cumulative Layout Shift):",
                clsScore.toFixed(3),
              );
            });
            clsObserver.observe({ type: "layout-shift", buffered: true });
          } catch (e) {}

          // Long Tasks
          try {
            const longTaskObserver = new PerformanceObserver((list) => {
              for (const entry of list.getEntries()) {
                console.warn(
                  "Long Task detected:",
                  Math.round(entry.duration),
                  "ms",
                );
              }
            });
            longTaskObserver.observe({ type: "longtask", buffered: true });
          } catch (e) {}
        }
      }, 0);
    });
  }
}

